#include <stdio.h>
int maxSubarraySum(int A[], int N) {
    int maxSum = A[0];
    int currentSum = A[0];
    for (int i = 1; i < N; i++) {
        currentSum = (currentSum + A[i] > A[i]) ? currentSum + A[i] : A[i];
        maxSum = (maxSum > currentSum) ? maxSum : currentSum;
    }
    return maxSum;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int maxSum = maxSubarraySum(A, N);
        int totalSum = 0;
        for (int i = 0; i < N; i++) {
            totalSum += A[i];
        }
        if (totalSum > 0) {
            maxSum = (maxSum > totalSum * K) ? maxSum : totalSum * K;
        }
        printf("%d\n", maxSum);
    }
    return 0;
}

