import java.util.Scanner;
public class Main {
    public static int maxSubarraySum(int[] A) {
        int maxSum = A[0];
        int currentSum = A[0];
        for (int i = 1; i < A.length; i++) {
            currentSum = (currentSum + A[i] > A[i]) ? currentSum + A[i] : A[i];
            maxSum = (maxSum > currentSum) ? maxSum : currentSum;
        }
        return maxSum;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int maxSum = maxSubarraySum(A);
            int totalSum = 0;
            for (int i = 0; i < N; i++) {
                totalSum += A[i];
            }
            if (totalSum > 0) {
                maxSum = (maxSum > totalSum * K) ? maxSum : totalSum * K;
            }
            System.out.println(maxSum);
        }
    }
}

